import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';

const OAuth2Client = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const clientId = 'mobile_app_client_123';
  const clientSecret = 'secret_abc123xyz456';

  const handleLogin = async () => {
    try {
      const authUrl = `https://oauth2.example.com/oauth/authorize?client_id=${clientId}&response_type=code&redirect_uri=yourapp://oauth2redirect`;
      // In a real app, you would open this URL in a browser or in-app browser
      // For MVP, we'll simulate the flow
      const authorizationCode = 'sample_auth_code_12345';
      await exchangeCodeForToken(authorizationCode);
    } catch (error) {
      Alert.alert('Login Error', error.message);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch('https://oauth2.example.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&client_id=${clientId}&client_secret=${clientSecret}&code=${code}&redirect_uri=yourapp://oauth2redirect`,
      });

      const data = await response.json();
      
      if (data.access_token) {
        setAccessToken(data.access_token);
        setRefreshToken(data.refresh_token || null);
        Alert.alert('Success', 'Logged in successfully');
      } else {
        throw new Error('Token exchange failed');
      }
    } catch (error) {
      Alert.alert('Token Error', error.message);
    }
  };

  const refreshAccessToken = async () => {
    if (!refreshToken) {
      Alert.alert('Error', 'No refresh token available');
      return;
    }

    try {
      const response = await fetch('https://oauth2.example.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=refresh_token&client_id=${clientId}&client_secret=${clientSecret}&refresh_token=${refreshToken}`,
      });

      const data = await response.json();
      
      if (data.access_token) {
        setAccessToken(data.access_token);
        Alert.alert('Success', 'Token refreshed');
      } else {
        throw new Error('Token refresh failed');
      }
    } catch (error) {
      Alert.alert('Refresh Error', error.message);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      <Button title="Login" onPress={handleLogin} />
      {accessToken && (
        <Button title="Refresh Token" onPress={refreshAccessToken} />
      )}
    </View>
  );
};

export default OAuth2Client;